const description =
  '伊的家華人基督教會的核心信仰——美國播道會（EFCA）十一條信仰宣言。';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let aboutPage: Awaited<ReturnType<typeof getAboutPage>> = null;

try {
  aboutPage = await getAboutPage('zh');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- EFCA 11-point Statement of Faith in Chinese ----------
const fallbackBeliefs = [
  {
    title: '一、神',
    content:
      '<p>我們相信獨一的真神，祂是永恆存在的三個位格——聖父、聖子、聖靈——每一位都完全是神，各有位格之分，卻在本質和目的上合而為一。祂是萬物的創造者、維持者和統治者。</p>',
